import React from "react";
import { User } from "../types/user";
import UserRow from "./UserRow";

interface TableProps {
  users: User[];
  filterText: string;
}

const Table: React.FC<TableProps> = ({ users, filterText }) => {
  if (users.length === 0) {
    return <div className="no-results">No users found for "{filterText}"</div>;
  }

  return (
    <table className="user-table">
      <thead>
        <tr>
          <th>Name</th>
          <th>Picture</th>
          <th>Location</th>
          <th>Email</th>
          <th>Phone</th>
          <th>Registered</th>
        </tr>
      </thead>
      <tbody>
        {users.map((user, index) => (
          <UserRow key={index} user={user} />
        ))}
      </tbody>
    </table>
  );
};

export default Table;
